#include <iostream>

template <typename T>
class PairBox {
    T first_;
    T second_;
public:
    PairBox(T first, T second) : first_(first), second_(second) {}
    const T& minimum() const { return second_ < first_ ? second_ : first_; }
    const T& maximum() const { return first_ < second_ ? second_ : first_; }
};

int main() {
    long long first{}, second{};
    if (!(std::cin >> first >> second)) return 1;
    PairBox<long long> values(first, second);
    std::cout << values.minimum() << ' ' << values.maximum() << '\n';
}
